import { Download, FileText, Search } from "lucide-react";
import { useState } from "react";
import { Card } from "../components/Card";
import { mockDocuments } from "../data/mockData";

export function DocumentCenter() {
  const [searchTerm, setSearchTerm] = useState("");

  const filteredDocs = mockDocuments.filter(
    (doc) =>
      doc.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      doc.orderId.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-semibold text-gray-900">
          Document Center
        </h1>
        <p className="text-gray-600 mt-1">
          Download all StructBay generated documents
        </p>
      </div>

      <Card>
        <div className="mb-6">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
            <input
              type="text"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              placeholder="Search by document name or order number..."
              className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="border-b border-gray-200">
                <th className="text-left py-3 px-4 text-sm font-medium text-gray-600">
                  Document Name
                </th>
                <th className="text-left py-3 px-4 text-sm font-medium text-gray-600">
                  Order Number
                </th>
                <th className="text-left py-3 px-4 text-sm font-medium text-gray-600">
                  Generated Date
                </th>
                <th className="text-left py-3 px-4 text-sm font-medium text-gray-600">
                  Status
                </th>
                <th className="text-left py-3 px-4 text-sm font-medium text-gray-600">
                  Action
                </th>
              </tr>
            </thead>
            <tbody>
              {filteredDocs.map((doc) => (
                <tr key={doc.id} className="border-b border-gray-100">
                  <td className="py-4 px-4">
                    <div className="flex items-center gap-3">
                      <div className="p-2 bg-red-50 rounded">
                        <FileText className="w-5 h-5 text-red-600" />
                      </div>
                      <div>
                        <p className="font-medium text-gray-900">{doc.name}</p>
                        <p className="text-xs text-gray-500">{doc.type.toUpperCase()}</p>
                      </div>
                    </div>
                  </td>
                  <td className="py-4 px-4 text-sm text-gray-900">
                    {doc.orderId}
                  </td>
                  <td className="py-4 px-4 text-sm text-gray-600">
                    {new Date(doc.generatedDate).toLocaleDateString("en-IN")}
                  </td>
                  <td className="py-4 px-4">
                    <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
                      Available
                    </span>
                  </td>
                  <td className="py-4 px-4">
                    <button className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors text-sm">
                      <Download className="w-4 h-4" />
                      Download
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          {filteredDocs.length === 0 && (
            <div className="text-center py-12">
              <FileText className="w-12 h-12 text-gray-400 mx-auto mb-3" />
              <p className="text-gray-500">No documents found</p>
            </div>
          )}
        </div>
      </Card>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <Card title="Customer Invoice">
          <p className="text-sm text-gray-600 mb-3">
            Invoice generated by StructBay for the customer
          </p>
          <div className="text-2xl font-semibold text-gray-900">
            {mockDocuments.filter((d) => d.name === "Customer Invoice").length}
          </div>
        </Card>

        <Card title="E-Way Bills">
          <p className="text-sm text-gray-600 mb-3">
            GST e-way bills for inter-state transport
          </p>
          <div className="text-2xl font-semibold text-gray-900">
            {mockDocuments.filter((d) => d.name === "E-Way Bill").length}
          </div>
        </Card>

        <Card title="Shipping Labels">
          <p className="text-sm text-gray-600 mb-3">
            Labels to be attached to shipments
          </p>
          <div className="text-2xl font-semibold text-gray-900">
            {mockDocuments.filter((d) => d.name === "Shipping Label").length}
          </div>
        </Card>

        <Card title="Packing Slips">
          <p className="text-sm text-gray-600 mb-3">
            Detailed packing information for orders
          </p>
          <div className="text-2xl font-semibold text-gray-900">
            {mockDocuments.filter((d) => d.name === "Packing Slip").length}
          </div>
        </Card>
      </div>
    </div>
  );
}
